mapper.select:
SELECT s.id AS value, s.id AS id, s.public_id::text AS publicKey, s.name AS label, s.name AS name, s.hospital_id AS hospitalId, h.public_id::text AS hospitalPublicKey, h.name AS hospitalName, s.ip_address AS ipAddress, s.port AS port, s.dicom_port AS dicomPort, (CASE WHEN s.ssl_enabled IS TRUE THEN 'https' ELSE 'http' END || '://' || s.ip_address || ':' || s.port) AS dicomServerBaseUrl, (CASE WHEN s.ssl_enabled IS TRUE THEN 'https' ELSE 'http' END || '://' || s.ip_address || ':' || s.port) AS dicomServerUiBaseUrl, ((CASE WHEN s.ssl_enabled IS TRUE THEN 'https' ELSE 'http' END || '://' || s.ip_address || ':' || s.port) || COALESCE(NULLIF(BTRIM(s.dicomweb_path), ''), '/dicom-web')) AS dicomwebBaseUrl, COALESCE(NULLIF(BTRIM(s.dicomweb_path), ''), '/dicom-web') AS dicomwebPath, s.viewer_base_url AS viewerBaseUrl, s.ae_title AS aeTitle, s.username AS username, s.is_active AS isActive FROM hospital_dicom_servers s INNER JOIN hospitals h ON h.id = s.hospital_id WHERE s.hospital_id = #{hospitalId} AND s.is_active != 2
AND ( NOT EXISTS ( SELECT 1 FROM hospital_dicom_routing_configs cfg WHERE cfg.hospital_id = s.hospital_id AND cfg.dicom_server_id = s.id AND cfg.is_active = 1 )
OR s.id = #{filter.includeDicomServerId}
)
AND ( s.name ILIKE CONCAT('%', #{filter.searchText}, '%') OR COALESCE(s.ip_address, '') ILIKE CONCAT('%', #{filter.searchText}, '%') OR s.port::text ILIKE CONCAT('%', #{filter.searchText}, '%') OR COALESCE(s.dicom_port, 4242)::text ILIKE CONCAT('%', #{filter.searchText}, '%') OR COALESCE(s.viewer_base_url, '') ILIKE CONCAT('%', #{filter.searchText}, '%') OR COALESCE(s.ae_title, '') ILIKE CONCAT('%', #{filter.searchText}, '%') OR COALESCE(s.username, '') ILIKE CONCAT('%', #{filter.searchText}, '%') )
ORDER BY s.is_active DESC, s.name ASC, s.id ASC
LIMIT #{filter.rowsPerPage} OFFSET #{filter.page}

SELECT DISTINCT u.id AS value, u.public_id::text AS publicKey, COALESCE( NULLIF( TRIM( CONCAT( COALESCE(u.first_name, ''), ' ', COALESCE(u.last_name, ''), CASE WHEN COALESCE(u.username, '') = '' THEN '' ELSE ' (' || u.username || ')' END ) ), '' ), u.username ) AS label FROM users u LEFT JOIN user_hospitals uh ON uh.user_id = u.id AND uh.is_active = 1 WHERE u.is_active = 1
AND uh.hospital_id = #{hospitalId}
AND ( u.username ILIKE CONCAT('%', #{filter.searchText}, '%') OR u.first_name ILIKE CONCAT('%', #{filter.searchText}, '%') OR u.last_name ILIKE CONCAT('%', #{filter.searchText}, '%') )
ORDER BY label ASC
LIMIT #{filter.rowsPerPage} OFFSET #{filter.page}

SELECT p.id AS value, p.public_id::text AS publicKey, CONCAT( COALESCE(p.patient_uid, ''), ' - ', COALESCE(NULLIF(TRIM(CONCAT(COALESCE(p.first_name, ''), ' ', COALESCE(p.last_name, ''))), ''), '') ) AS label FROM patients p WHERE p.is_active = 1 AND p.hospital_id = #{hospitalId}
AND ( p.patient_uid ILIKE CONCAT('%', #{filter.searchText}, '%') OR p.first_name ILIKE CONCAT('%', #{filter.searchText}, '%') OR p.last_name ILIKE CONCAT('%', #{filter.searchText}, '%') OR TRIM(CONCAT(COALESCE(p.first_name, ''), ' ', COALESCE(p.last_name, ''))) ILIKE CONCAT('%', #{filter.searchText}, '%') OR COALESCE(p.phone_number, '') ILIKE CONCAT('%', #{filter.searchText}, '%') )
ORDER BY p.id DESC
LIMIT #{filter.rowsPerPage} OFFSET #{filter.page}

SELECT DISTINCT r.id AS value, r.public_id::text AS publicKey, r.name AS label FROM user_groups ug INNER JOIN roles r ON r.id = ug.role_id LEFT JOIN user_hospitals uh ON uh.user_id = ug.user_id AND uh.is_active = 1 LEFT JOIN hospitals h ON h.id = uh.hospital_id AND h.is_active = 1 WHERE ug.is_active = 1 AND r.is_active = 1
AND uh.hospital_id = #{hospitalId}
AND uh.hospital_id = #{actorHospitalId}
AND ( uh.hospital_id IS NOT NULL OR NOT EXISTS ( SELECT 1 FROM user_hospitals uh_scope WHERE uh_scope.user_id = ug.user_id AND uh_scope.is_active = 1 ) )
AND UPPER(COALESCE(r.code, '')) <> 'USER_HOSPITAL_SCOPE_ALL'
AND r.name ILIKE CONCAT('%', #{filter.searchText}, '%')
ORDER BY r.name ASC
LIMIT #{filter.rowsPerPage} OFFSET #{filter.page}
